sql:
SELECT AVG(gdp_per_capita) AS average_gdp_per_capita, SUM(population) AS total_population
FROM country_economic_data
WHERE year = 1988;

SELECT country_name 
FROM countries 
WHERE gdp_per_capita > (SELECT AVG(gdp_per_capita) FROM countries);

SELECT AVG(gdp_per_capita) AS average_gdp_per_capita
FROM country_economic_data
WHERE gdp_per_capita > (SELECT AVG(gdp_per_capita) FROM country_economic_data);

WITH ranked_countries AS (
    SELECT c.country_name, c.official_language, ced.gdp_per_capita,
           RANK() OVER (ORDER BY ced.gdp_per_capita DESC) AS rank
    FROM countries c
    JOIN country_economic_data ced ON c.country_id = ced.country_id
    WHERE c.official_language = (
        SELECT official_language FROM countries WHERE country_name = 'United States'
    ) AND ced.year = (
        SELECT MAX(year) FROM country_economic_data WHERE country_id = (
            SELECT country_id FROM countries WHERE country_name = 'United States'
        )
    )
)
SELECT rank FROM ranked_countries WHERE country_name = 'United States';

external_knowledge:
- Wealth per person is synonymous with GDP per capita in economic terms; 
- The geographic areas refer to the distinct regions identified in the regions table;
- "Highest average wealth" corresponds to the highest average GDP per capita.
